import React, { useState, useEffect } from 'react';
import { useNavigate, useParams, Link } from 'react-router-dom';
import axios from 'axios';

function VulnerabilityForm() {
  const { id } = useParams();
  const nav = useNavigate();
  const [form, setForm] = useState({
    vulnerability_type: '',
    software_version: '',
    system_name: '',
    patch_status: 'Open',
    threat_level: 3
  });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (id) {
      axios.get(`/api/vulnerabilities/${id}`).then(res => setForm(res.data));
    }
  }, [id]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    if (id) {
      await axios.put(`/api/vulnerabilities/${id}`, form);
    } else {
      await axios.post('/api/vulnerabilities', form);
    }
    setLoading(false);
    nav('/vulnerabilities');
  };

  return (
    <div className="page">
      <h2>{id ? 'Редактировать' : 'Новая'} уязвимость</h2>
      <form onSubmit={handleSubmit} className="form">
        <div className="field">
          <label>Тип уязвимости</label>
          <input name="vulnerability_type" value={form.vulnerability_type} onChange={e => setForm({...form, vulnerability_type: e.target.value})} required />
        </div>
        <div className="row">
          <div className="field">
            <label>Версия ПО</label>
            <input name="software_version" value={form.software_version || ''} onChange={e => setForm({...form, software_version: e.target.value})} />
          </div>
          <div className="field">
            <label>Система</label>
            <input name="system_name" value={form.system_name || ''} onChange={e => setForm({...form, system_name: e.target.value})} />
          </div>
        </div>
        <div className="row">
          <div className="field">
            <label>Статус исправления</label>
            <select name="patch_status" value={form.patch_status} onChange={e => setForm({...form, patch_status: e.target.value})}>
              <option value="Open">Открыта</option>
              <option value="InProgress">В работе</option>
              <option value="Fixed">Исправлена</option>
              <option value="Reopened">Переоткрыта</option>
            </select>
          </div>
          <div className="field">
            <label>Уровень угрозы (1-5)</label>
            <select name="threat_level" value={form.threat_level} onChange={e => setForm({...form, threat_level: Number(e.target.value)})}>
              <option value="1">1 - Низкий</option>
              <option value="2">2 - Ниже среднего</option>
              <option value="3">3 - Средний</option>
              <option value="4">4 - Высокий</option>
              <option value="5">5 - Критический</option>
            </select>
          </div>
        </div>
        <div className="form-actions">
          <button type="submit" className="btn save" disabled={loading}>{loading ? 'Сохранение...' : 'Сохранить'}</button>
          <Link to="/vulnerabilities" className="btn cancel">Отмена</Link>
        </div>
      </form>
    </div>
  );
}

export default VulnerabilityForm;
